  ('food-tech-moex-00899', 'food-tech', 'food-tech-moex-097-9af4f2a0', 'sub-food-tech-01', NULL, 'essay', '食品樣品中的化合物 A 用比色法（Colorimetry）進行分析，請用比爾定律（Beer''s
law）計算下列條件下的待測樣品中化合物 A的含量，結果請用 mg/100 g 來表示。
測定條件：2.5 g樣品被灰化；灰化後的樣品用1 mL酸溶解，定容至250 mL；
取 1 mL 進行呈色反應後，定容至 50 mL；樣品在 600 nm 波長下測得吸光度
（absorbance）是 0.543；莫耳吸光係數（molar absorptivity）為 1574 L/(g.cm)；
分光光度計比色管（QuartzCell）內徑為1 cm。（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:12:03+00:00", "source_pdf_sha1": "14770941f53f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "020", "s": "3001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "食品分析與檢驗", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "food", "db_exam_id": "food-tech"}'::jsonb, NULL),
